import{_ as e,o as a,c as o,ag as d}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"SIM800L GPS/GPRS AT Commands","description":"Quick reference for SIM800 series AT commands; full manual linked below.","frontmatter":{"title":"SIM800L GPS/GPRS AT Commands","description":"Quick reference for SIM800 series AT commands; full manual linked below."},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/sim800l-gps-gprs-at-commands.md","filePath":"microcontrollers-and-socs/raspberry-pi/sim800l-gps-gprs-at-commands.md"}'),r={name:"microcontrollers-and-socs/raspberry-pi/sim800l-gps-gprs-at-commands.md"};function s(i,t,l,n,c,m){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="sim800l-gps-gprs-at-commands" tabindex="-1">SIM800L GPS/GPRS AT Commands <a class="header-anchor" href="#sim800l-gps-gprs-at-commands" aria-label="Permalink to &quot;SIM800L GPS/GPRS AT Commands&quot;">​</a></h1><p>Reference for the SIMCom <strong>SIM800</strong> GSM/GPRS module family (SIM800L breakout boards on Pi UART).</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="../../.gitbook/assets/SIM800_Series_AT_Command_Manual_V1.09.pdf">SIM800 Series AT Command Manual V1.09 (PDF)</a></li></ul><h2 id="serial-setup" tabindex="-1">Serial setup <a class="header-anchor" href="#serial-setup" aria-label="Permalink to &quot;Serial setup&quot;">​</a></h2><ul><li>Default baud often <strong>115200</strong> (check your module; some ship at 9600)</li><li>8N1, no flow control typical</li><li>Pi: enable UART, wire TX↔RX, common GND; use 3.3 V logic levels</li></ul><h2 id="essential-commands" tabindex="-1">Essential commands <a class="header-anchor" href="#essential-commands" aria-label="Permalink to &quot;Essential commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Purpose</th></tr></thead><tbody><tr><td><code>AT</code></td><td>Ping — expect <code>OK</code></td></tr><tr><td><code>AT+CPIN?</code></td><td>SIM PIN status</td></tr><tr><td><code>AT+CSQ</code></td><td>Signal quality (0–31, 99 = unknown)</td></tr><tr><td><code>AT+CREG?</code> / <code>AT+CGREG?</code></td><td>Network / GPRS registration</td></tr><tr><td><code>AT+COPS?</code></td><td>Operator</td></tr><tr><td><code>AT+CGDCONT=1,&quot;IP&quot;,&quot;&lt;apn&gt;&quot;</code></td><td>Define PDP context (set your carrier APN)</td></tr><tr><td><code>AT+CGACT=1,1</code></td><td>Activate PDP context</td></tr><tr><td><code>AT+CIPSTART=&quot;TCP&quot;,&quot;host&quot;,port</code></td><td>Open TCP (multi-connection firmware)</td></tr><tr><td><code>AT+CIPSEND</code></td><td>Send data on open socket</td></tr><tr><td><code>AT+CIPSHUT</code></td><td>Close connection / shut IP stack</td></tr></tbody></table><h2 id="sms-selection" tabindex="-1">SMS (selection) <a class="header-anchor" href="#sms-selection" aria-label="Permalink to &quot;SMS (selection)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Purpose</th></tr></thead><tbody><tr><td><code>AT+CMGF=1</code></td><td>Text mode SMS</td></tr><tr><td><code>AT+CMGS=&quot;&lt;number&gt;&quot;</code></td><td>Send SMS (terminate with Ctrl+Z)</td></tr><tr><td><code>AT+CMGL=&quot;ALL&quot;</code></td><td>List messages</td></tr></tbody></table><h2 id="gps-sim800-variants-with-gnss" tabindex="-1">GPS (SIM800 variants with GNSS) <a class="header-anchor" href="#gps-sim800-variants-with-gnss" aria-label="Permalink to &quot;GPS (SIM800 variants with GNSS)&quot;">​</a></h2><p>GNSS-capable modules add <code>AT+CGNSPWR</code>, <code>AT+CGNSINF</code>, etc. — see the PDF for your exact firmware.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Send <code>AT</code> after power-up until <code>OK</code> (module boot takes seconds)</li><li>Use a adequate PSU — peak current spikes can brown out the Pi USB supply</li><li>For full syntax, error codes, and USSD/voice commands, use the linked manual</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">Raspberry Pi</a></li></ul>',16)])])}const S=e(r,[["render",s]]);export{h as __pageData,S as default};
